atom.template:
if (!_ctx.init) {
  _ctx.init = true;
  // Glow nucleus
  _ctx.nucleus = sdk.createSphere(1.5, 0, 0xff3366, {x:0, y:0, z:0}).mesh;
  _ctx.nucleus.material.emissive.setHex(0xff0055);
  _ctx.nucleus.material.emissiveIntensity = 2;
  // Orbit Rings
  const r1 = new THREE.Mesh(new THREE.TorusGeometry(4, 0.05, 16, 100), new THREE.MeshBasicMaterial({color: 0x444444}));
  r1.rotation.x = Math.PI/2;
  scene.add(r1);
  // Electrons
  _ctx.e1 = sdk.createSphere(0.3, 0, 0x00ffff, {x:4, y:0, z:0}).mesh;
  _ctx.e2 = sdk.createSphere(0.3, 0, 0x00ffff, {x:0, y:5, z:0}).mesh;
}
let s = S.Speed || 1;
_ctx.e1.position.set(Math.cos(t*s)*4, 0, Math.sin(t*s)*4);
_ctx.e2.position.set(0, Math.cos(t*s*1.2)*5, Math.sin(t*s*1.2)*5);

gravity.template:
if (!_ctx.init) {
  _ctx.init = true;
  // Static floor
  sdk.createFloor(0x1a202c);
  // Dynamic falling objects (Cannon.js handles gravity automatically!)
  sdk.createSphere(1, 5, 0xff3366, {x: -2, y: 15, z: 0});
  sdk.createBox(2, 2, 2, 10, 0x33ccff, {x: 2, y: 25, z: 1});
}
// Engine updates position automatically based on physics SDK!

solar_system.template:
if (!_ctx.init) {
  _ctx.init = true;
  _ctx.sun = sdk.createSphere(3, 0, 0xffaa00, {x:0, y:0, z:0}).mesh;
  _ctx.sun.material.emissive.setHex(0xff5500);
  _ctx.sun.material.emissiveIntensity = 1.5;

  _ctx.earth = sdk.createSphere(1, 0, 0x0077ff, {x:10, y:0, z:0}).mesh;

  // Starfield
  const stars = new THREE.BufferGeometry();
  const starPos = [];
  for(let i=0; i<500; i++) {
    starPos.push((Math.random()-0.5)*100, (Math.random()-0.5)*100, (Math.random()-0.5)*100);
  }
  stars.setAttribute('position', new THREE.Float32BufferAttribute(starPos, 3));
  scene.add(new THREE.Points(stars, new THREE.PointsMaterial({color: 0xffffff})));
}
let s = S.Speed || 1;
_ctx.sun.rotation.y = t * 0.2;
_ctx.earth.position.set(Math.cos(t*s)*10, 0, Math.sin(t*s)*10);
